  // ── Convex-hull group overlay ────────────────────────────────────────────
  if (getComputedStyle(chartDiv).position === 'static') chartDiv.style.position = 'relative';
  const hullCanvas = document.createElement('canvas');
  hullCanvas.style.cssText = 'position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;';
  chartDiv.appendChild(hullCanvas);

  // Stores computed hull polygons so the click handler can do hit-testing.
  const hullPolys = []; // [{gid, poly, circle}]  poly=null means circle fallback

  function redrawHulls() {
    hullCanvas.width  = chartDiv.offsetWidth;
    hullCanvas.height = chartDiv.offsetHeight;
    const ctx = hullCanvas.getContext('2d');
    ctx.clearRect(0, 0, hullCanvas.width, hullCanvas.height);
    hullPolys.length = 0;

    // Step 1 — get raw (pre-zoom) positions from ECharts item layout.
    // These are in the series group's LOCAL coordinate space.
    // We also track which IDs are currently rendered so the posStore fallback
    // never supplies positions for nodes that aren't actually visible.
    const localPos = new Map();
    const displayedIds = new Set();
    try {
      const sm = ec.getModel().getSeriesByIndex(0);
      if (sm) {
        const dat = sm.getData();
        for (let i = 0; i < dat.count(); i++) {
          const id = dat.getId(i);
          displayedIds.add(id);
          const layout = dat.getItemLayout(i);
          if (layout && isFinite(layout.x) && isFinite(layout.y))
            localPos.set(id, [layout.x, layout.y]);
        }
      }
    } catch (_) {}
    // Fallback: use posStore, but ONLY for IDs that ECharts is actually rendering.
    // This prevents stale positions for collapsed/hidden nodes from leaking through.
    if (localPos.size === 0) {
      for (const id of displayedIds) {
        const pos = posStore.get(id);
        if (pos) localPos.set(id, [pos.x, pos.y]);
      }
    } else {
      // Partial fill: getItemLayout worked for some nodes; patch missing ones from posStore.
      for (const id of displayedIds) {
        if (!localPos.has(id)) {
          const pos = posStore.get(id);
          if (pos) localPos.set(id, [pos.x, pos.y]);
        }
      }
    }
    if (localPos.size === 0) return;

    // Step 2 — build a local→screen transform by reading the series group's
    // world transform.  This is what makes the hull follow zoom/pan correctly.
    let toScreen = (x, y) => [x, y];
    try {
      const sm = ec.getModel().getSeriesByIndex(0);
      const view = sm && ec.getViewOfSeriesModel(sm);
      const g = view && view.group;
      if (g) {
        if (typeof g.transformCoordToGlobal === 'function') {
          toScreen = (x, y) => g.transformCoordToGlobal(x, y);
        } else {
          const m = g.transform;
          if (m) toScreen = (x, y) => [m[0]*x + m[2]*y + m[4], m[1]*x + m[3]*y + m[5]];
        }
      }
    } catch (_) {}

    // Step 3 — convert all local positions to screen pixels.
    const idToPx = new Map();
    for (const [id, [lx, ly]] of localPos) {
      const [sx, sy] = toScreen(lx, ly);
      if (isFinite(sx) && isFinite(sy)) idToPx.set(id, [sx, sy]);
    }
    if (idToPx.size === 0) return;

    // A group's hull should only be drawn when the group itself AND every
    // ancestor group is expanded — otherwise the group's members aren't visible.
    const ancestorsExpanded = gid => {
      const g = gInfo.get(gid);
      if (!g) return false;
      if (!g.expanded) return false;
      return g.parentGid ? ancestorsExpanded(g.parentGid) : true;
    };

    // Sort so outer groups (lower level number) are drawn first (behind inner ones).
    const sorted = [...gInfo.entries()]
      .filter(([gid]) => ancestorsExpanded(gid))
      .sort((a, b) => (a[1].level || 1) - (b[1].level || 1));

    const PAD = 22;
    for (const [gid, g] of sorted) {
      const pts = [];
      for (const mid of g.members)   { const p = idToPx.get(mid);  if (p) pts.push(p); }
      for (const sgid of (g.subGroups || [])) { const p = idToPx.get(sgid); if (p) pts.push(p); }
      if (pts.length === 0) continue;

      const color = g.color || '#2E9CDB';
      const isOuter = (g.level || 1) === 1;

      let poly;
      if (pts.length < 3) {
        // 1-2 points: draw a circle instead of a hull
        const cx = pts.reduce((s, p) => s + p[0], 0) / pts.length;
        const cy = pts.reduce((s, p) => s + p[1], 0) / pts.length;
        ctx.save();
        ctx.beginPath();
        ctx.arc(cx, cy, PAD + 18, 0, Math.PI * 2);
        ctx.fillStyle   = hexToRgba(color, isOuter ? 0.08 : 0.13);
        ctx.strokeStyle = hexToRgba(color, isOuter ? 0.40 : 0.60);
        ctx.lineWidth   = isOuter ? 2 : 1.5;
        if (!isOuter) ctx.setLineDash([5, 3]);
        ctx.fill();
        ctx.stroke();
        ctx.restore();

        ctx.save();
        ctx.font = `bold ${isOuter ? 11 : 10}px sans-serif`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        const lbl = g.displayLabel;
        const tm  = ctx.measureText(lbl);
        ctx.fillStyle = 'rgba(255,255,255,0.78)';
        ctx.fillRect(cx - tm.width / 2 - 3, cy - PAD - 28, tm.width + 6, 15);
        ctx.fillStyle = color;
        ctx.fillText(lbl, cx, cy - PAD - 21);
        ctx.restore();
        hullPolys.push({ gid, poly: null, circle: { cx, cy, r: PAD + 18 } });
        continue;
      }

      const hull = d3.polygonHull(pts);
      if (!hull) continue;

      const cx = d3.polygonCentroid(hull)[0];
      const cy = d3.polygonCentroid(hull)[1];

      // Expand each vertex outward from centroid by PAD pixels.
      poly = hull.map(([px, py]) => {
        const dx = px - cx, dy = py - cy;
        const len = Math.sqrt(dx * dx + dy * dy) || 1;
        return [px + (dx / len) * PAD, py + (dy / len) * PAD];
      });

      ctx.save();
      ctx.beginPath();
      ctx.moveTo(poly[0][0], poly[0][1]);
      for (let i = 1; i < poly.length; i++) ctx.lineTo(poly[i][0], poly[i][1]);
      ctx.closePath();
      ctx.fillStyle   = hexToRgba(color, isOuter ? 0.08 : 0.13);
      ctx.strokeStyle = hexToRgba(color, isOuter ? 0.40 : 0.60);
      ctx.lineWidth   = isOuter ? 2 : 1.5;
      if (!isOuter) ctx.setLineDash([5, 3]);
      ctx.fill();
      ctx.stroke();
      ctx.restore();

      // Label just above the topmost hull vertex.
      const topY = Math.min(...poly.map(p => p[1]));
      ctx.save();
      ctx.font = `bold ${isOuter ? 11 : 10}px sans-serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      const lbl = g.displayLabel;
      const tm  = ctx.measureText(lbl);
      ctx.fillStyle = 'rgba(255,255,255,0.78)';
      ctx.fillRect(cx - tm.width / 2 - 3, topY - 18, tm.width + 6, 15);
      ctx.fillStyle = color;
      ctx.fillText(lbl, cx, topY - 11);
      ctx.restore();
      hullPolys.push({ gid, poly });
    }
  }

  ec.on('finished', redrawHulls);
  // Redraw on every render frame so hulls follow zoom/pan in real-time.
  let _hullRaf = null;
  ec.getZr().on('rendered', () => {
    if (_hullRaf) cancelAnimationFrame(_hullRaf);
    _hullRaf = requestAnimationFrame(() => { _hullRaf = null; redrawHulls(); });
  });
  // ── End hull overlay ─────────────────────────────────────────────────────

  const directed = !!spec.directed;

  // D3-managed position store — persists across rerenders, never touched by ECharts
  const posStore = new Map();
  // Track which node/group IDs were displayed in the previous render to detect true newcomers
  let prevFilteredIds = new Set();

  function updateMethodButtons() {
    methodBtns.forEach((btn, id) => {
      const active = id === activeGroupMethod;
      btn.style.background    = active ? 'var(--accent-bg,#e8f0fe)' : 'transparent';
      btn.style.color         = active ? 'var(--accent-text,#1a73e8)' : 'var(--text,#444)';
      btn.style.borderColor   = active ? 'var(--accent,#1a73e8)' : 'var(--border2,#ccc)';
      btn.style.fontWeight    = active ? '600' : 'normal';
    });
  }

  function applyGrouping(method) {
    activeGroupMethod = method;
    ({ levels, gInfo, l1Colors, groupingMethod, groupingFields } =
      buildHierarchicalGroups(allNodes, links, _C, method));
    idToL1Gid = levels[0] || new Map();
    l1Count = [...gInfo.values()].filter(g => g.level === 1).length;
    l2Count = [...gInfo.values()].filter(g => g.level === 2).length;
    groupConns = computeGroupConns();
    posStore.clear();
    prevFilteredIds = new Set();
    noteEl.textContent = buildGroupingNote();
    noteEl.style.display = (l1Count > 0 || l2Count > 0) ? '' : 'none';
    grpSec.style.display = (l1Count > 0 || l2Count > 0) ? '' : 'none';
    updateMethodButtons();
    rerender();
  }
  const titleOpt = spec.title ? { text: spec.title, top: 5, left: 'center', textStyle: { color: t.text, fontSize: 13 } } : undefined;
  const ROLE_COLOR = { both: '#2E9CDB', source: '#2E9CDB', dest: '#2E9CDB' };
  const GROUP_COLOR_TWIN = '#2E9CDB';
  let useColorEdgesByCategory = false;
  let useColorByCategory = false;
  let edgeOpacity = 0.5;
  let nodeOpacity = 1.0;
  let nodeSizeScale = 0.2;
  let showTwinLabels = false;
  let leafFillWhite = true;
  let nodeLabelFontSize = 10;
  let edgeLabelFontSize = 10;
  let arrowheadMinSize = 8;
  let showArrowheads = true;
  let searchQuery = '';

  function rerender() {
    if (grpBtn) {
      const anyCollapsedL1 = [...gInfo.values()].filter(g => g.level === 1).some(g => !g.expanded);
      grpBtn.textContent = anyCollapsedL1 ? 'Expand L1 groups' : 'Collapse L1 groups';
    }
    if (catBtn) {
      const anyVis = categories.some(c => catVisible.get(c));
      catBtn.textContent = anyVis ? 'Hide all' : 'Show all';
    }
    legendItems.forEach(({ el, cat }) => {
      const on = catVisible.get(cat);
      el.style.opacity = on ? '1' : '0.35';
      el.style.textDecoration = on ? 'none' : 'line-through';
    });

    // Display nodes — walk levels outermost-first; show the first collapsed group found
    const idToDisp = new Map();
    const dispEntries = [];
    const seenGroups = new Set();
    allNodes.forEach(n => {
      let collapsedGid = null;
      for (let lvl = 0; lvl < levels.length; lvl++) {
        const gid = levels[lvl].get(n.id);
        if (gid && !gInfo.get(gid).expanded) { collapsedGid = gid; break; }
      }
      if (collapsedGid) {
        if (!seenGroups.has(collapsedGid)) { seenGroups.add(collapsedGid); dispEntries.push({ kind: 'group', gid: collapsedGid, info: gInfo.get(collapsedGid) }); }
        idToDisp.set(n.id, collapsedGid);
      } else {
        dispEntries.push({ kind: 'node', node: n });
        idToDisp.set(n.id, n.id);
      }
    });

    // Filter + dedupe links
    const visLinks = links.filter(l => !l.label || catVisible.get(l.label));
    const linkMap = new Map();
    visLinks.forEach(l => {
      const s = idToDisp.get(l.source), tg = idToDisp.get(l.target);
      if (!s || !tg || s === tg) return;
      const key = [s, tg].sort().join('|') + '|' + (l.label || '');
      if (!linkMap.has(key)) linkMap.set(key, { source: s, target: tg, label: l.label, color: l.color, value: +(l.value || 1), count: 1 });
      else { const e = linkMap.get(key); e.value += +(l.value || 1); e.count++; }
    });
    const dispLinks = [...linkMap.values()];

    // Apply search filtering if query exists
    let filteredEntries = dispEntries;
    let filteredLinks = dispLinks;
    if (searchQuery.length > 0) {
      const matchedIds = new Set();
      const neighborIds = new Set();

      // Find all nodes that match the search query
      dispEntries.forEach(d => {
        const id = d.kind === 'group' ? d.gid : d.node.id;
        const name = d.kind === 'group' ? d.info.displayLabel : (d.node.name || d.node.id);
        if (id.toString().toLowerCase().includes(searchQuery) || name.toString().toLowerCase().includes(searchQuery)) {
          matchedIds.add(id);
        }
      });

      // Find all neighbors of matched nodes
      dispLinks.forEach(l => {
        if (matchedIds.has(l.source)) neighborIds.add(l.target);
        if (matchedIds.has(l.target)) neighborIds.add(l.source);
      });

      // Filter entries: keep matched nodes + neighbors
      const visibleIds = new Set([...matchedIds, ...neighborIds]);
      filteredEntries = dispEntries.filter(d => {
        const id = d.kind === 'group' ? d.gid : d.node.id;
        return visibleIds.has(id);
      });

      // Filter links: keep only those connecting visible nodes
      filteredLinks = dispLinks.filter(l => visibleIds.has(l.source) && visibleIds.has(l.target));
    }

    // ── D3 force simulation for stable positions ────────────────────────────
    const W = Math.max(chartDiv.offsetWidth || 0, 200);
    const H = Math.max(chartDiv.offsetHeight || 0, 380);
    const isFirstLayout = posStore.size === 0;

    // Snapshot which IDs were already in posStore — used to detect newcomers in seeding.
    const preExistingIds = new Set(posStore.keys());

    if (isFirstLayout) {
      // Arrange in an evenly-spaced circle so nodes start spread out rather than
      // clustered near the origin (D3's default random init).
      // Seed groups on a larger outer ring, individual nodes on a smaller inner ring,
      // so the simulation starts with communities already somewhat separated.
      const groups0 = filteredEntries.filter(d => d.kind === 'group');
      const indivs0 = filteredEntries.filter(d => d.kind !== 'group');
      const outerR = Math.min(W, H) * 0.42;
      const innerR = Math.min(W, H) * 0.22;
      groups0.forEach((d, i) => {
        const angle = (i / Math.max(1, groups0.length)) * Math.PI * 2;
        posStore.set(d.gid, { x: W / 2 + outerR * Math.cos(angle), y: H / 2 + outerR * Math.sin(angle) });
      });
      indivs0.forEach((d, i) => {
        const angle = (i / Math.max(1, indivs0.length)) * Math.PI * 2;
        posStore.set(d.node.id, { x: W / 2 + innerR * Math.cos(angle), y: H / 2 + innerR * Math.sin(angle) });
      });
    } else {
      // Pass 1: seed collapsed groups (they appear from member expansion being reversed)
      filteredEntries.forEach(d => {
        if (d.kind !== 'group') return;
        const displayId = d.gid;
        if (posStore.has(displayId)) return;
        const grp = d.info;
        if (grp.savedPos) {
          posStore.set(displayId, grp.savedPos);
        } else {
          // Centroid of members' last known positions
          let sx = 0, sy = 0, cnt = 0;
          grp.members.forEach(mid => { const p = posStore.get(mid); if (p) { sx += p.x; sy += p.y; cnt++; } });
          if (cnt > 0) {
            posStore.set(displayId, { x: sx / cnt, y: sy / cnt });
          } else {
            // Members not yet in posStore — this group just appeared because its parent
            // was expanded. Seed near the nearest ancestor group that has a known position.
            const anyMember = grp.members[0];
            let parentL1gid = null;
            if (anyMember) {
              for (let lvl = 0; lvl < levels.length - 1; lvl++) {
                const pgid = levels[lvl].get(anyMember);
                if (pgid && posStore.has(pgid)) { parentL1gid = pgid; break; }
              }
            }
            const parentPos = parentL1gid ? posStore.get(parentL1gid) : null;
            const jitter = 40;
            posStore.set(displayId, parentPos
              ? { x: parentPos.x + (Math.random() - 0.5) * jitter, y: parentPos.y + (Math.random() - 0.5) * jitter }
              : { x: W / 2, y: H / 2 });
          }
        }
      });

      // Pass 2: gather new individual nodes by parent so we can spread them on
      // an evenly-spaced circle (random scatter gives unreadable dense blobs for
      // large groups).
      const newNodesByParent = new Map();
      filteredEntries.forEach(d => {
        if (d.kind !== 'node') return;
        const id = d.node.id;
        if (posStore.has(id)) return;
        let pgid = null;
        for (let lvl = levels.length - 1; lvl >= 0; lvl--) {
          const gid = levels[lvl]?.get(id);
          if (gid && posStore.has(gid)) { pgid = gid; break; }
        }
        const bucket = pgid || '__none__';
        if (!newNodesByParent.has(bucket)) newNodesByParent.set(bucket, []);
        newNodesByParent.get(bucket).push(id);
      });

      // Seed new nodes randomly within a disk. A regular circle produces
      // concentric-ring artifacts once groupAttract and collision settle;
      // random placement lets charge+link+collision find a natural layout.
      newNodesByParent.forEach((nodeIds, pgid) => {
        const center = pgid !== '__none__' && posStore.has(pgid)
          ? posStore.get(pgid)
          : { x: W / 2, y: H / 2 };
        const r = Math.max(200, Math.sqrt(nodeIds.length) * 60);
        nodeIds.forEach(nodeId => {
          const angle = Math.random() * Math.PI * 2;
          const dist  = r * Math.sqrt(Math.random()); // uniform within disk
          posStore.set(nodeId, { x: center.x + Math.cos(angle) * dist, y: center.y + Math.sin(angle) * dist });
        });
      });
    }

    // Warm-start: all nodes begin at their last known positions; newcomers begin at
    // their seeded position. No pinning — let the whole graph shift slightly to
    // accommodate newly revealed nodes, matching natural force-directed behaviour.
    const d3Nodes = filteredEntries.map(d => {
      const id = d.kind === 'group' ? d.gid : d.node.id;
      const p = posStore.get(id);
      const isGroup = d.kind === 'group';
      const grpSz = isGroup ? Math.max(22, Math.min(72, 14 + Math.sqrt(groupConns.get(id) || d.info.members.length) * 4)) : 0;
      // Identify which expanded L1 community anchors this node so the group-attraction
      // force can keep community members clustered near their original group position.
      let l1Anchor = null;
      if (!isGroup) {
        const l1gid = idToL1Gid.get(id);
        if (l1gid && gInfo.get(l1gid).expanded) l1Anchor = l1gid;
      } else if (d.info.level === 2) {
        const anyMember = d.info.members[0];
        const l1gid = anyMember ? idToL1Gid.get(anyMember) : null;
        if (l1gid && gInfo.get(l1gid).expanded) l1Anchor = l1gid;
      }
      return { id, x: p ? p.x : W / 2, y: p ? p.y : H / 2, isGroup, grpSz, l1Anchor };
    });

    // Only run D3 when the set of displayed nodes actually changed (expand/collapse).
    // Pure visual rerenders (opacity, color, search with same nodes) skip D3.
    const curFilteredIds = new Set(filteredEntries.map(d => d.kind === 'group' ? d.gid : d.node.id));
    const hasNewNodes = isFirstLayout || [...curFilteredIds].some(id => !prevFilteredIds.has(id));
    if (hasNewNodes) {
      const simIdSet = curFilteredIds;
      // Parallel edges between the same pair (same source+target, different labels)
      // each contribute independent link force. Deduplicate to 1 per unordered pair
      // so high-connectivity pairs don't collapse into each other.
      const d3PairSeen = new Set();
      const d3Links = filteredLinks
        .filter(l => {
          if (!simIdSet.has(l.source) || !simIdSet.has(l.target)) return false;
          const pair = l.source < l.target ? `${l.source}|${l.target}` : `${l.target}|${l.source}`;
          if (d3PairSeen.has(pair)) return false;
          d3PairSeen.add(pair);
          return true;
        })
        .map(l => ({ source: l.source, target: l.target }));

      const makeLinkForce = () => d3.forceLink(d3Links).id(d => d.id)
        .distance(l => {
          const sg = l.source.isGroup, tg = l.target.isGroup;
          return (sg && tg) ? 400 : (sg || tg) ? 230 : 150;
        })
        .strength(l => {
          const sg = l.source.isGroup, tg = l.target.isGroup;
          return (sg && tg) ? 0.04 : 0.12;
        });

      if (isFirstLayout) {
        // Phase 1: repulsion + collision only at constant alpha so nodes spread out
        // freely before links are introduced. Without this, link forces immediately
        // pull connected groups back into a pile during the first ticks.
        const d3sim = d3.forceSimulation(d3Nodes)
          .force('charge', d3.forceManyBody().strength(d => d.isGroup ? -(600 + d.grpSz * d.grpSz * 0.4) : -450))
          .force('x', d3.forceX(W / 2).strength(0.01))
          .force('y', d3.forceY(H / 2).strength(0.01))
          .force('collide', d3.forceCollide(d => d.isGroup ? Math.max(150, d.grpSz * 2.5) : 50))
          .alphaDecay(0)
          .stop();
        for (let i = 0; i < 150; i++) d3sim.tick();
        // Phase 2: introduce links on the already-spread positions and run to settle.
        d3sim.force('link', makeLinkForce()).alphaDecay(0.0228).alpha(1);
        for (let i = 0; i < 450; i++) { d3sim.tick(); if (d3sim.alpha() < 0.001) break; }
      } else {
        const d3sim = d3.forceSimulation(d3Nodes)
          .force('link', makeLinkForce())
          .force('charge', d3.forceManyBody().strength(d => d.isGroup ? -(600 + d.grpSz * d.grpSz * 0.4) : -600))
          .force('x', d3.forceX(W / 2).strength(0.01))
          .force('y', d3.forceY(H / 2).strength(0.01))
          .force('collide', d3.forceCollide(d => d.isGroup ? Math.max(150, d.grpSz * 2.5) : 50))
          // Only pull L2 group nodes toward their community anchor.
          // Individual nodes must NOT have this force — it creates concentric-ring
          // equilibria where charge+groupAttract+collision lock nodes into orbits.
          // Individual node cohesion comes from intra-community link force instead.
          .force('groupAttract', alpha => {
            d3Nodes.forEach(node => {
              if (!node.l1Anchor || !node.isGroup) return;
              const grp = gInfo.get(node.l1Anchor);
              const target = grp && grp.savedPos;
              if (!target) return;
              node.vx += (target.x - node.x) * 0.06 * alpha;
              node.vy += (target.y - node.y) * 0.06 * alpha;
            });
          })
          .stop();
        for (let i = 0; i < 300; i++) { d3sim.tick(); if (d3sim.alpha() < 0.001) break; }
      }
      d3Nodes.forEach(n => posStore.set(n.id, { x: n.x, y: n.y }));
    }
    prevFilteredIds = curFilteredIds;

    // Degree on display set
    const degree = new Map();
    filteredLinks.forEach(l => {
      degree.set(l.source, (degree.get(l.source) || 0) + 1);
      degree.set(l.target, (degree.get(l.target) || 0) + 1);
    });

    // Calculate most common category for each node
    const nodeMostCommonCat = new Map();
    if (useColorByCategory && categories.length > 0) {
      filteredLinks.forEach(l => {
        if (l.label && catColor.has(l.label)) {
          const catMap = (id) => {
            if (!nodeMostCommonCat.has(id)) nodeMostCommonCat.set(id, new Map());
            const m = nodeMostCommonCat.get(id);
            m.set(l.label, (m.get(l.label) || 0) + 1);
          };
          catMap(l.source);
          catMap(l.target);
        }
      });
    }
    const sortedDeg = [...degree.values()].sort((a, b) => b - a);
    const maxLabels = Math.min(25, Math.max(5, Math.ceil(sortedDeg.length * 0.15)));
    const labelCutoff = sortedDeg.length ? sortedDeg[Math.min(maxLabels - 1, sortedDeg.length - 1)] : 0;
    const sourceSet = new Set(filteredLinks.map(l => l.source));
    const destSet   = new Set(filteredLinks.map(l => l.target));

    const nodes = filteredEntries.map(d => {
      // Helper to get node color based on category or default
      const getNodeColor = (nodeId) => {
        if (useColorByCategory && nodeMostCommonCat.has(nodeId)) {
          const catMap = nodeMostCommonCat.get(nodeId);
          const mostCommonCat = [...catMap.entries()].sort((a, b) => b[1] - a[1])[0][0];
          return catColor.get(mostCommonCat) || GROUP_COLOR_TWIN;
        }
        return GROUP_COLOR_TWIN;
      };

      if (d.kind === 'group') {
        const grp = d.info;
        const totalConns = groupConns.get(d.gid) || grp.members.length;
        const sz = Math.max(28, Math.min(80, 16 + Math.sqrt(totalConns) * 4)) * nodeSizeScale;
        const isL1 = grp.level === 1;
        const gpos = posStore.get(d.gid);
        const gc = grp.color || '#2E9CDB';
        return {
          id: d.gid,
          name: `L${grp.level} ${grp.displayLabel}`,
          symbol: 'circle',
          symbolSize: sz,
          ...(gpos ? { x: gpos.x, y: gpos.y } : {}),
          // Solid filled circle: groups are visually prominent, leaves are hollow.
          // Border thickness signals depth — L1 thicker than L2.
          itemStyle: { color: gc, borderColor: '#ffffff', borderWidth: isL1 ? 2 : 1, opacity: nodeOpacity },
          label: {
            show: true, position: 'inside',
            formatter: `{lv|L${grp.level}}\n{nm|${grp.displayLabel}}\n{ct|(${grp.members.length})}`,
            rich: {
              lv: { fontSize: nodeLabelFontSize + 4, fontWeight: 'bold', color: '#ffffff',
                    textBorderColor: gc, textBorderWidth: 1, lineHeight: nodeLabelFontSize + 7,
                    align: 'center' },
              nm: { fontSize: nodeLabelFontSize, fontWeight: 'bold', color: '#ffffff',
                    textBorderColor: gc, textBorderWidth: 1 },
              ct: { fontSize: nodeLabelFontSize, color: 'rgba(255,255,255,0.85)',
                    textBorderColor: gc, textBorderWidth: 1, align: 'center',
                    lineHeight: nodeLabelFontSize + 4 },
            },
          },
          _isGroup: true, _gid: d.gid,
        };
      }
      const n = d.node;
      const id = n.id;
      const deg = degree.get(id) || 1;
      const szBase = n.size || (n.value != null
        ? Math.max(16, Math.min(72, Math.sqrt(n.value) * 4))
        : Math.max(10, Math.min(56, 8 + Math.sqrt(deg) * 4)));
      const sz = szBase * nodeSizeScale;
      const role = (sourceSet.has(id) && destSet.has(id)) ? 'both' : sourceSet.has(id) ? 'source' : 'dest';
      const l1gid = idToL1Gid.get(id);
      const communityColor = l1gid ? l1Colors.get(l1gid) : null;
      // Find deepest expanded group containing this node
      let groupGid = null;
      for (let lvl = levels.length - 1; lvl >= 0; lvl--) {
        const gid = levels[lvl]?.get(id);
        if (gid && gInfo.get(gid)?.expanded) { groupGid = gid; break; }
      }
      const inGroup = groupGid != null;
      const leafColor = useColorByCategory ? getNodeColor(id) : (n.color || communityColor || ROLE_COLOR[role]);
      const storedPos = posStore.get(id);
      return {
        id,
        name: n.name || id,
        symbolSize: sz,
        ...(storedPos ? { x: storedPos.x, y: storedPos.y } : {}),
        itemStyle: {
          color: leafFillWhite ? '#ffffff' : 'transparent',
          borderColor: leafColor,
          borderWidth: inGroup ? 2.5 : 1.5,
          opacity: nodeOpacity,
        },
        label: {
          show: !(groupGid && gInfo.get(groupGid)?.kind === 'twin' && !showTwinLabels) && (deg >= labelCutoff || inGroup),
          position: 'inside',
          fontSize: nodeLabelFontSize,
          color: leafColor,
          textBorderColor: '#ffffff',
          textBorderWidth: 2,
          fontWeight: inGroup ? 'bold' : 'normal',
        },
        _inGroup: inGroup,
        _groupGid: groupGid,
      };
    });

    const linkValues = filteredLinks.map(l => l.value).filter(v => v != null && v > 0);
    const minLV = linkValues.length ? Math.min(...linkValues) : 1;
    const maxLV = linkValues.length ? Math.max(...linkValues) : 1;
    const scaleWidth = v => (v != null && maxLV > minLV)
      ? 1 + ((v - minLV) / (maxLV - minLV)) * 5
      : (v != null ? 2 : 1);
    const echLinks = filteredLinks.map(l => {
      const w = scaleWidth(l.value);
      return {
        source: l.source, target: l.target,
        name: l.label != null ? String(l.label) + (l.count > 1 ? ' ×' + l.count : '') : undefined,
        value: l.value,
        label: { show: false, formatter: l.label != null ? String(l.label) : '', fontSize: edgeLabelFontSize, color: t.text },
        emphasis: { label: { show: l.label != null, color: t.text } },
        symbolSize: [0, Math.max(arrowheadMinSize, Math.min(25, w * 3.5))],
        lineStyle: { width: w, opacity: edgeOpacity * 0.75, color: useColorEdgesByCategory ? (l.color || (l.label ? catColor.get(l.label) : null) || null) : '#000000' },
      };
    });

    const option = {
      backgroundColor: '#ffffff',
      color: _C,
      title: titleOpt,
      tooltip: {
        formatter: p => {
          if (p.dataType === 'edge') {
            return p.data.name ? p.data.name + (p.data.value != null ? ' (' + p.data.value + ')' : '')
              : p.data.source + (directed ? ' → ' : ' — ') + p.data.target;
          }
          if (p.data._isGroup) {
            const info = gInfo.get(p.data._gid);
            const list = info.members.slice(0, 8).join(', ') + (info.members.length > 8 ? ', …' : '');
            const kindLabel = info.kind === 'attribute'
              ? (info.level === 1 ? 'Attribute group (L1)' : `Attribute sub-group (L${info.level})`)
              : info.kind === 'louvain' ? 'Louvain community'
              : 'Twin sub-group';
            return '<b>' + p.name + '</b><br/><i>' + kindLabel + '</i><br/>' + list + '<br/><i>click to expand</i>';
          }
          return p.name + (p.data._inGroup ? '<br/><i>click to collapse group</i>' : '');
        },
      },
      legend: { show: false },
      series: [{
        id: 'graph-main',
        type: 'graph',
        layout: 'none',
        data: nodes,
        links: echLinks,
        roam: true,
        label: { show: false },
        edgeLabel: { show: false, fontSize: 10 },
        edgeSymbol: (directed && showArrowheads) ? ['none', 'arrow'] : ['none', 'none'],
        lineStyle: { curveness: spec.curved ? 0.2 : 0 },
        emphasis: { focus: 'adjacency', lineStyle: { width: 4 }, edgeLabel: { show: true, fontSize: 10 } },
      }],
    };
    ec.setOption(option, { replaceMerge: ['series'] });
  }

  updateMethodButtons();
  rerender();

  // Flag set synchronously by the ECharts node-click handler so the hull
  // click handler below knows to skip hull hit-testing for that click.
  let ecClickHandled = false;

  ec.on('click', params => {
    if (params.dataType !== 'node') return;
    const d = params.data;
    if (!d) return;
    ecClickHandled = true;
    if (d._isGroup) {
